###############################################################################
# Purpose: Perform pseudotime trajectory analysis on selected cell clusters
#          using Monocle2. This example uses CK3D clusters 18 (PEN) and 20 (CZE)
#          to infer a trajectory between them.
# Input:  - Metadata file (CK3D_metadata_res1.txt)
#         - Cluster count matrices (CK3D_cluster18_count.rds, CK3D_cluster20_count.rds)
#         - (generated by extract_cluster_counts.R)
# Output: - Monocle CellDataSet object (RDS)
#         - Differential expression table (DEGs between cell types)
###############################################################################

library(monocle)
library(dplyr)
library(Seurat)
library(ggplot2)

# Set working directory (adjust to your path)
setwd("path/to/your/analysis_directory")   # e.g., "bchi_analysis_res"

# ----------------------------------------------------------------------------
# 1. Load metadata and cluster count matrices
# ----------------------------------------------------------------------------
metadata <- read.table("CK3D_metadata_res1.txt", header = TRUE)

# Load count matrices for the two clusters of interest
counts_c18 <- readRDS("CK3D_cluster18_count.rds")
counts_c20 <- readRDS("CK3D_cluster20_count.rds")

# ----------------------------------------------------------------------------
# 2. Prepare phenoData (cell metadata) with a celltype label
# ----------------------------------------------------------------------------
# Subset metadata for cells in each cluster
pd_c18 <- metadata[colnames(counts_c18), , drop = FALSE]
pd_c18 <- as.data.frame(pd_c18)
pd_c18$celltype <- "PEN_c18"

pd_c20 <- metadata[colnames(counts_c20), , drop = FALSE]
pd_c20 <- as.data.frame(pd_c20)
pd_c20$celltype <- "CZE_c20"

# Combine both clusters
pd <- rbind(pd_c18, pd_c20)
data <- cbind(counts_c18, counts_c20)

# ----------------------------------------------------------------------------
# 3. Prepare featureData (gene information)
# ----------------------------------------------------------------------------
# Use gene names from one matrix (all matrices share the same genes)
fd <- data.frame(GeneName = rownames(data))
rownames(fd) <- fd$GeneName

# Create AnnotatedDataFrame objects for Monocle
pd <- new("AnnotatedDataFrame", data = pd)
fd <- new("AnnotatedDataFrame", data = fd)

# ----------------------------------------------------------------------------
# 4. Build the CellDataSet and estimate size factors & dispersions
# ----------------------------------------------------------------------------
cds <- newCellDataSet(data,
                      phenoData = pd,
                      featureData = fd,
                      expressionFamily = negbinomial.size())

cds <- estimateSizeFactors(cds)
cds <- estimateDispersions(cds)

# ----------------------------------------------------------------------------
# 5. Detect genes expressed in at least 10 cells
# ----------------------------------------------------------------------------
cds <- detectGenes(cds, min_expr = 0.1)
expressed_genes <- rownames(subset(fData(cds), num_cells_expressed >= 10))

# ----------------------------------------------------------------------------
# 6. Differential expression test to identify genes that vary with celltype
# ----------------------------------------------------------------------------
diff_test <- differentialGeneTest(cds[expressed_genes, ],
                                  fullModelFormulaStr = "~celltype",
                                  cores = 1)

# Extract significant DEGs (qval < 0.01) and order by qval
deg <- subset(diff_test, qval < 0.01)
deg <- deg[order(deg$qval, decreasing = FALSE), ]

# ----------------------------------------------------------------------------
# 7. Use top 2000 DEGs as ordering genes for trajectory
# ----------------------------------------------------------------------------
ordering_genes <- rownames(deg[1:min(2000, nrow(deg)), ])
cds <- setOrderingFilter(cds, ordering_genes)

# ----------------------------------------------------------------------------
# 8. Dimensionality reduction (DDRTree) and cell ordering
# ----------------------------------------------------------------------------
cds <- reduceDimension(cds, max_components = 2, method = "DDRTree")
cds <- orderCells(cds)

# ----------------------------------------------------------------------------
# 9. Save results
# ----------------------------------------------------------------------------
saveRDS(cds, file = "CK3D_c18c20_monocle.rds")
write.table(deg, file = "CK3D_c18c20_monocle_DEG.txt",
            sep = "\t", row.names = TRUE, col.names = TRUE, quote = FALSE)
